const row = $json;
const rawPhone = String(row.phone_number || row.telefono || '').trim();

// Limpieza para formatos como :p512777XXXX, p:521999..., +52..., etc.
let normalized = rawPhone
  .replace(/^\s*:?p\s*/i, '')
  .replace(/[^\d+]/g, '');

// Conservamos solo dígitos para validar longitud
let digits = normalized.replace(/\D/g, '');

// Reglas para MX/WhatsApp
if (digits.length === 10) {
  digits = `52${digits}`;
} else if (digits.length === 11 && digits.startsWith('1')) {
  digits = `52${digits}`;
}

if (digits.length === 12 && digits.startsWith('52')) {
  normalized = `+${digits}`;
} else if (digits.length === 13 && digits.startsWith('521')) {
  normalized = `+${digits}`;
} else {
  normalized = `+${digits}`;
}

const campaign = String(row.campaign_name || '').toLowerCase().trim();
const ad = String(row.ad_name || '').toLowerCase().trim();
const form = String(row.form_name || '').toLowerCase().trim();

let property = {
  property_id: 'REEMPLAZAR_PUBLIC_ID_CAUCEL',
  property_title: 'Casa en Caucel',
  property_zone: 'Caucel',
  template_name: 'caucel_info',
  template_language: 'es_MX',
  source_name: 'Facebook Lead Ads - Caucel'
};

if (campaign.includes('caucel') || ad.includes('caucel') || form.includes('caucel')) {
  property = {
    property_id: 'REEMPLAZAR_PUBLIC_ID_CAUCEL',
    property_title: 'Casa en Caucel',
    property_zone: 'Caucel',
    template_name: 'caucel_info',
    template_language: 'es_MX',
    source_name: 'Facebook Lead Ads - Caucel'
  };
}

const paymentMethod = row['¿con_qué_forma_de_pago_o_crédito_planeas_comprar?'] || row['¿cuál_es_tu_método_de_compra_o_tipo_de_crédito?'] || '';
const buyTimeline = row['¿para_cuándo_necesitas_tener_lista_tu_casa?'] || row['¿qué_tan_pronto_te_gustaría_mudarte?'] || '';

// Permite escoger plantilla desde la fila del Sheet (si viene), con fallback por propiedad
const templateNameFromSheet = String(row.template_name || row.template || row.chatwoot_template || '').trim();
const templateLanguageFromSheet = String(row.template_language || row.chatwoot_template_language || '').trim();

return [{
  json: {
    ...row,
    phone_original: rawPhone,
    phone_clean: normalized,
    phone_digits: digits,
    payment_method: paymentMethod,
    buy_timeline: buyTimeline,
    template_name_selected: templateNameFromSheet || property.template_name,
    template_language_selected: templateLanguageFromSheet || property.template_language,
    template_category_selected: 'MARKETING',
    ...property
  }
}];

