const base = $('Merge_row_y_easybroker').item.json;
const response = $json;
const payload = Array.isArray(response.payload) ? response.payload : [];

const clean = String(base.phone_clean || '');
const digits = String(base.phone_digits || '');

const found = payload.find((c) => {
  const phone = String(c.phone_number || '');
  const phoneDigits = phone.replace(/\D/g, '');
  return phone === clean || phoneDigits === digits || phoneDigits === `52${digits}`;
}) || payload[0] || null;

const inbox4 = found?.contact_inboxes?.find(ci => Number(ci?.inbox?.id) === 4) || null;

return [{
  json: {
    ...base,
    chatwoot_contact_exists: Boolean(found),
    chatwoot_contact_id: found?.id || null,
    chatwoot_contact_source_id: inbox4?.source_id || null,
    chatwoot_contact_raw: found || null
  }
}];

const prior = $('Resolver_contacto_chatwoot').item.json;
const response = $json || {};

const payload = response.payload || {};
const contactFromPayload = payload.contact || null;
const contactInboxFromPayload = payload.contact_inbox || null;

const pickFirstObject = (value) => {
  if (!value) return null;
  if (Array.isArray(value)) {
    for (const item of value) {
      const found = pickFirstObject(item);
      if (found) return found;
    }
    return null;
  }
  return (typeof value === 'object') ? value : null;
};

// Preferimos rutas conocidas de Chatwoot (payload.contact) antes de objetos genéricos
const candidates = [
  contactFromPayload,
  response.contact,
  response.data?.contact,
  response.result?.contact,
  response.data,
  response.result,
  response,
].filter(Boolean);

let contact = null;
for (const c of candidates) {
  const found = pickFirstObject(c);
  if (found) {
    contact = found;
    break;
  }
}

const contactId = Number(
  prior.chatwoot_contact_id ||
  contactFromPayload?.id ||
  contactFromPayload?.contact_id ||
  contactInboxFromPayload?.contact_id ||
  contact?.id ||
  contact?.contact_id ||
  0
) || null;

const inboxesFromPayload = Array.isArray(contactFromPayload?.contact_inboxes) ? contactFromPayload.contact_inboxes : [];
const inboxesFromContact = Array.isArray(contact?.contact_inboxes) ? contact.contact_inboxes : [];
const inboxesFromPrior = Array.isArray(prior?.chatwoot_contact_raw?.contact_inboxes) ? prior.chatwoot_contact_raw.contact_inboxes : [];
const allInboxes = [...inboxesFromPayload, ...inboxesFromContact, ...inboxesFromPrior];
const inbox4 = allInboxes.find(ci => Number(ci?.inbox?.id) === 4 || Number(ci?.inbox_id) === 4);

const sourceId = String(
  prior.chatwoot_contact_source_id ||
  payload?.contact_inbox?.source_id ||
  contactInboxFromPayload?.source_id ||
  inbox4?.source_id ||
  contactFromPayload?.source_id ||
  contact?.source_id ||
  contact?.contact_inbox?.source_id ||
  ''
).trim() || null;

if (!contactId) {
  throw new Error(`No se pudo resolver chatwoot_contact_id. Claves respuesta: ${Object.keys(response).join(', ')}`);
}

return [{
  json: {
    ...prior,
    chatwoot_contact_id: contactId,
    chatwoot_contact_source_id: sourceId,
    chatwoot_contact_status: prior.chatwoot_contact_exists ? 'existing_updated' : 'created',
    chatwoot_contact_raw_resolved: contactFromPayload || contact || response,
    needs_source_lookup: !sourceId
  }
}];

const base = $('Normalizar_ids_contacto_chatwoot').item.json;
const response = $json || {};

const candidates = [
  response,
  response.payload,
  Array.isArray(response.payload) ? response.payload[0] : null,
  response.data,
  response.contact,
  response.payload?.contact,
  response.data?.contact,
  response.result,
  response.result?.contact,
].filter(Boolean);

let contact = null;
for (const c of candidates) {
  if (Array.isArray(c)) {
    contact = c.find(i => i && typeof i === 'object') || contact;
  } else if (c && typeof c === 'object') {
    contact = c;
  }
  if (contact) break;
}

const inboxes = Array.isArray(contact?.contact_inboxes) ? contact.contact_inboxes : [];
const inbox4 = inboxes.find(ci => Number(ci?.inbox?.id) === 4 || Number(ci?.inbox_id) === 4);
const sourceId = String(inbox4?.source_id || contact?.source_id || '').trim();

if (!sourceId) {
  throw new Error(`No se pudo resolver source_id del inbox 4 incluso consultando detalle de contacto. Respuesta: ${JSON.stringify(response)}`);
}

return [{
  json: {
    ...base,
    chatwoot_contact_source_id: sourceId,
    needs_source_lookup: false,
    chatwoot_contact_detail_raw: contact || response
  }
}];

